import React, { useEffect, useState } from "react";
import "./Admin.css";

const Admin = () => {
  const [stats, setStats] = useState([]);

  const [form, setForm] = useState({
    title: "",
    description: "",
    location: "",
    date: "",
    category: "IT",
    image: ""
  });

  // загрузка статистики
  const loadStats = () => {
    fetch("http://localhost:5000/admin/stats")
      .then(res => res.json())
      .then(data => {
        console.log("ADMIN DATA:", data);

        if (Array.isArray(data)) {
          setStats(data);
        } else {
          setStats([]);
        }
      });
  };

  useEffect(() => {
    loadStats();
  }, []);

  const handleDelete = async (id) => {
  if (!window.confirm("Видалити подію?")) return;

  try {
    const res = await fetch(`http://localhost:5000/events/${id}`, {
      method: "DELETE"
    });

    const data = await res.json();

    if (!res.ok) {
      alert(data.error);
      return;
    }

    // обновляем список без перезагрузки
    setStats(prev => prev.filter(event => event.id !== id));

  } catch (err) {
    console.error(err);
  }
};

  // добавление события
  const handleSubmit = async (e) => {
    e.preventDefault();

    const res = await fetch("http://localhost:5000/admin/events", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(form)
    });

    const data = await res.json();

    if (!res.ok) {
      alert(data.error);
      return;
    }

    alert("Подія створена 🎉");

    setForm({
      title: "",
      description: "",
      location: "",
      date: "",
      category: "IT",
      image: ""
    });

    loadStats(); // обновляем статистику
  };

  return (
    <div className="admin-page">

      <h1>Адмін панель</h1>

      {/* СТАТИСТИКА */}
      <div className="admin-stats">
        <h2>Статистика подій</h2>

        {Array.isArray(stats) && stats.length > 0 ? (
          stats.map(event => (
            <div key={event.id} className="stat-card">
              <h3>{event.title}</h3>
              <p>Реєстрацій: {event.registrations}</p>

              <button
                className="delete-btn"
                onClick={() => handleDelete(event.id)}
              >
                Видалити
              </button>
            </div>
          ))
        ) : (
          <p>Немає даних</p>
        )}
      </div>

      {/* ФОРМА */}
      <div className="admin-form">
        <h2>Додати подію</h2>

        <form onSubmit={handleSubmit}>
          <input
            placeholder="Назва"
            value={form.title}
            onChange={(e) =>
              setForm({ ...form, title: e.target.value })
            }
          />

          <input
            placeholder="Опис"
            value={form.description}
            onChange={(e) =>
              setForm({ ...form, description: e.target.value })
            }
          />

          <input
            placeholder="Місто"
            value={form.location}
            onChange={(e) =>
              setForm({ ...form, location: e.target.value })
            }
          />

          <input
            type="datetime-local"
            value={form.date}
            onChange={(e) =>
              setForm({ ...form, date: e.target.value })
            }
          />

          <select
            value={form.category}
            onChange={(e) =>
              setForm({ ...form, category: e.target.value })
            }
          >
            <option>IT</option>
            <option>Business</option>
            <option>Design</option>
            <option>Marketing</option>
          </select>

          <input
            placeholder="URL картинки"
            value={form.image}
            onChange={(e) =>
              setForm({ ...form, image: e.target.value })
            }
          />

          <button type="submit">Створити</button>
        </form>
      </div>

    </div>
  );
};

export default Admin;
